/**
 * MedX dashboard layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Dashboard grid areas for KPI widgets.
 */
const DASHBOARD_TOKENS = Object.freeze({
  primary: { value: "layout-dashboard-primary", scope: "layout" },
  secondary: { value: "layout-dashboard-secondary", scope: "layout" },
  muted: { value: "layout-dashboard-muted", scope: "layout" },
  accent: { value: "layout-dashboard-accent", scope: "layout" },
  surface: { value: "layout-dashboard-surface", scope: "layout" },
});

const DASHBOARD_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const DASHBOARD_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const dashboardRegistry = new Map();
const DASHBOARD_listeners = new Set();
let DASHBOARD_seq = 0;

function createDashboardId(prefix = "medx-layout-dashboard") {
  DASHBOARD_seq += 1;
  return `${prefix}-${DASHBOARD_seq}`;
}

function registerDashboard(config = {}) {
  const entryId = config.id ?? createDashboardId();
  const preset = DASHBOARD_PRESETS[config.preset ?? "default"] ?? DASHBOARD_PRESETS.default;
  const token = DASHBOARD_TOKENS[config.token ?? preset.token] ?? DASHBOARD_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: DASHBOARD_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  dashboardRegistry.set(entryId, entry);
  notifyDashboardListeners("register", entry);
  return entry;
}

function updateDashboard(id, patch = {}) {
  const entry = dashboardRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyDashboardListeners("update", entry);
  return entry;
}

function resolveDashboard(id) {
  const entry = dashboardRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listDashboardEntries(filter = {}) {
  let items = Array.from(dashboardRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onDashboardEvent(listener) {
  DASHBOARD_listeners.add(listener);
  return () => DASHBOARD_listeners.delete(listener);
}

function notifyDashboardListeners(type, entry) {
  for (const listener of DASHBOARD_listeners) {
    try {
      listener({ type, entry, registrySize: dashboardRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:dashboard] listener error", err.message);
    }
  }
}

function getDashboardMetrics() {
  const items = listDashboardEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(DASHBOARD_TOKENS).length,
    presets: Object.keys(DASHBOARD_PRESETS).length,
  };
}

async function runMedxDashboard() {
  console.log("[medx:ui:layout:dashboard] runtime initialized");
  console.log(`[medx:ui:layout:dashboard] tokens=${Object.keys(DASHBOARD_TOKENS).length} presets=${Object.keys(DASHBOARD_PRESETS).length}`);

  const events = [];
  onDashboardEvent((e) => events.push(e.type));

  const domains = Object.keys(DASHBOARD_SUPPLY_CHAIN);
  const presets = Object.keys(DASHBOARD_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerDashboard({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/dashboard" },
    });
  }

  const first = listDashboardEntries()[0];
  if (first) updateDashboard(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getDashboardMetrics();
  const resolved = first ? resolveDashboard(first.id) : null;

  console.log(`[medx:ui:layout:dashboard] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:dashboard] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:dashboard] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:dashboard] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:dashboard] bootstrap complete");
}

module.exports = runMedxDashboard;
